  ('elementary-acfc4025-moex-00930', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-35395ec3', 'sub-elementary-acfc4025-03', NULL, 'single_choice', '一個3千歐姆電阻器，流過的電流為0.012安培，此電阻器所消耗之功率為何？', '["36瓦特", "4.32瓦特", "3.6瓦特", "0.432瓦特"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "822b349b9b10", "answer_pdf_sha1": "ae0b3bbd27f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基本電學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL)
